use typed_arena::Arena;

struct Node<'a> {
    value: i32,
    children: Vec<&'a Node<'a>>,
}

// The arena must be created by the caller and passed in — its lifetime
// scopes all the references that come out of it.
fn build_tree<'a>(arena: &'a Arena<Node<'a>>) -> &'a Node<'a> {
    let left = arena.alloc(Node { value: 2, children: vec![] });
    let right = arena.alloc(Node { value: 3, children: vec![] });
    arena.alloc(Node { value: 1, children: vec![left, right] })
}

fn main() {
    let arena = Arena::new();
    let root = build_tree(&arena);
    println!("root={}, children={}", root.value, root.children.len());
    for child in &root.children {
        println!("  child={}", child.value);
    }
}

