use typed_arena::Arena;
use std::cell::Cell;

struct Node<'a> {
    id: u32,
    next: Cell<Option<&'a Node<'a>>>,
}

fn main() {
    // The arena must have an explicit lifetime annotation that matches the node
    let arena: Arena<Node<'_>> = Arena::new();

    let a = arena.alloc(Node { id: 1, next: Cell::new(None) });
    let b = arena.alloc(Node { id: 2, next: Cell::new(None) });

    // Cycles are safe with Cell — no runtime borrow count, just a raw value swap
    a.next.set(Some(b));
    b.next.set(Some(a));

    let mut cur = a;
    for _ in 0..4 {
        print!("{} -> ", cur.id);
        cur = cur.next.get().unwrap();
    }
    println!("...");
}

