use bumpalo::Bump;
use bumpalo::collections::Vec as BumpVec;

// Option A: return a bumpalo Vec tied to the bump lifetime
fn collect_into_bump<'a>(bump: &'a Bump, items: &[i32]) -> BumpVec<'a, i32> {
    let mut v = BumpVec::with_capacity_in(items.len(), bump);
    for &x in items {
        v.push(x);
    }
    v
}

// Option B: convert to std Vec when leaving the bump scope
fn process_std(bump: &Bump, items: &[i32]) -> Vec<i32> {
    let mut v = BumpVec::with_capacity_in(items.len(), bump);
    for &x in items {
        v.push(x);
    }
    v.into_iter().collect()  // copy into heap-allocated std Vec
}

fn main() {
    let bump = Bump::new();
    let data = [1i32, 2, 3, 4, 5];

    // Stay in bump scope for zero-copy intermediate processing
    let bumped = collect_into_bump(&bump, &data);
    let sum: i32 = bumped.iter().sum();
    println!("sum in bump: {}", sum);

    // Or convert to std Vec to return across bump lifetime
    let owned = process_std(&bump, &data);
    println!("owned: {:?}", owned);
}

