use typed_arena::Arena;

struct Expr<'src> {
    name: &'src str,
    next: Option<*const Expr<'src>>,  // raw pointer avoids lifetime coupling
}

// Simpler: single lifetime that covers both source borrows and arena lifetime
fn parse<'a>(source: &'a str, arena: &'a Arena<Expr<'a>>) -> &'a Expr<'a> {
    let first = arena.alloc(Expr {
        name: &source[0..5],
        next: None,
    });
    let second = arena.alloc(Expr {
        name: &source[5..10],
        next: Some(first as *const _),
    });
    second
}

fn main() {
    let source = String::from("helloworld");
    let arena: Arena<Expr<'_>> = Arena::new();
    let root = parse(&source, &arena);
    println!("root: {}", root.name);
    if let Some(next_ptr) = root.next {
        println!("next: {}", unsafe { &*next_ptr }.name);
    }
}

