use typed_arena::Arena;

// Arenas shine for tree/graph structures where many nodes are created together
// and freed together, especially when nodes reference each other.

struct TreeNode<'a> {
    value: i32,
    children: Vec<&'a TreeNode<'a>>,
}

impl<'a> TreeNode<'a> {
    fn sum(&self) -> i32 {
        self.value + self.children.iter().map(|c| c.sum()).sum::<i32>()
    }
}

fn build_complete_tree<'a>(arena: &'a Arena<TreeNode<'a>>, depth: u32, value: &mut i32) -> &'a TreeNode<'a> {
    let children = if depth > 0 {
        vec![
            build_complete_tree(arena, depth - 1, value),
            build_complete_tree(arena, depth - 1, value),
        ]
    } else {
        vec![]
    };
    *value += 1;
    arena.alloc(TreeNode { value: *value, children })
}

fn main() {
    let arena = Arena::new();
    let root = build_complete_tree(&arena, 4, &mut 0);
    println!("sum = {}", root.sum());
    println!("allocated {} nodes", arena.len());
    // All nodes freed at once when `arena` drops here
}
